#include <stdio.h>
#include <stdlib.h>

#define MAX_N 1000

int heap[MAX_N];
int heapSize;

void heapifyUp(int index) {
    while (index > 0) {
        int parent = (index - 1) / 2;
        if (heap[index] < heap[parent]) {
            int tmp = heap[index];
            heap[index] = heap[parent];
            heap[parent] = tmp;
            index = parent;
        } else {
            break;
        }
    }
}

void insert(int value) {
    heap[heapSize] = value;
    heapifyUp(heapSize);
    heapSize++;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        heapSize = 0;
        for (int i = 0; i < N; ++i) {
            int v; scanf("%d", &v);
            insert(v);
            for (int j = 0; j < heapSize; ++j) {
                if (j) printf(" ");
                printf("%d", heap[j]);
            }
            printf("\n");
        }
    }
    return 0;
}

