import java.io.*;
import java.util.*;

public class Main {
    private static void heapifyUp(int idx, List<Integer> heap) {
        while (idx > 0) {
            int parent = (idx - 1) / 2;
            if (heap.get(idx) < heap.get(parent)) {
                int tmp = heap.get(idx);
                heap.set(idx, heap.get(parent));
                heap.set(parent, tmp);
                idx = parent;
            } else break;
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            List<Integer> heap = new ArrayList<>(N);
            for (int i = 0; i < N; i++) {
                int v = Integer.parseInt(br.readLine().trim());
                heap.add(v);
                heapifyUp(heap.size() - 1, heap);
                for (int j = 0; j < heap.size(); j++) {
                    if (j > 0) out.append(' ');
                    out.append(heap.get(j));
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

