import sys

def heapify_up(idx, heap):
    while idx > 0:
        parent = (idx - 1) // 2
        if heap[idx] < heap[parent]:
            heap[idx], heap[parent] = heap[parent], heap[idx]
            idx = parent
        else:
            break

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        heap = []
        for _ in range(N):
            v = int(next(it))
            heap.append(v)
            heapify_up(len(heap) - 1, heap)
            out_lines.append(' '.join(map(str, heap)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

